```java
import java.util.*;

class Solution {
    public List<List<Integer>> countKeys(String s) {
        // 统计每个按键被按下的次数
        Map<Character, Integer> cnt = new HashMap<>();
        int i = 0, n = s.length();

        while (i < n) {
            // 优先匹配失灵按键对应的转义串
            if (i + 1 < n && s.charAt(i) == 'u' && s.charAt(i + 1) == 'u') {
                cnt.put('j', cnt.getOrDefault('j', 0) + 1);
                i += 2;
            } else if (i + 1 < n && s.charAt(i) == 't' && s.charAt(i + 1) == 't') {
                cnt.put('b', cnt.getOrDefault('b', 0) + 1);
                i += 2;
            } else {
                // 否则就是正常按键
                char c = s.charAt(i);
                cnt.put(c, cnt.getOrDefault(c, 0) + 1);
                i++;
            }
        }

        // 转成列表后排序
        List<Character> list = new ArrayList<>(cnt.keySet());
        Collections.sort(list, (a, b) -> {
            int ca = cnt.get(a), cb = cnt.get(b);
            if (ca != cb) {
                return cb - ca; // 次数降序
            }
            return a - b; // 字符升序
        });

        // 构造答案
        List<List<Integer>> ans = new ArrayList<>();
        for (char c : list) {
            List<Integer> pair = new ArrayList<>();
            pair.add(encode(c));
            pair.add(cnt.get(c));
            ans.add(pair);
        }

        return ans;
    }

    // 字符转义
    private int encode(char c) {
        if (c >= '0' && c <= '9') {
            return c - '0';
        }
        return c - 'a' + 10;
    }
}
